40	//
41	// copy_if -- Predicated Copy
42	//
43	
44	template <class PrdTensor,
45	          class SrcEngine, class SrcLayout,
46	          class DstEngine, class DstLayout>
47	CUTE_HOST_DEVICE
48	void
49	copy_if(PrdTensor                    const& pred,
50	        Tensor<SrcEngine, SrcLayout> const& src,
51	        Tensor<DstEngine, DstLayout>      & dst)
52	{
53	  using SrcType = typename SrcEngine::value_type;
54	  using DstType = typename DstEngine::value_type;
55	
56	  CUTE_UNROLL
57	  for (int i = 0; i < size(dst); ++i) {
58	    if (pred(i)) {
59	      dst(i) = static_cast<DstType>(static_cast<SrcType>(src(i)));
60	    }
61	  }
62	}
