276	template <class Base>
277	struct AutoFilter {
278	  Base const& base;
279	  CUTE_HOST_DEVICE AutoFilter(Base const& b) : base(b) {}
280	};
281	
282	// Specialization for AutoFilter
283	template <class CopyOp,
284	          class SrcEngine, class SrcLayout,
285	          class DstEngine, class DstLayout>
286	CUTE_HOST_DEVICE
287	void
288	copy(AutoFilter<CopyOp>           const& copy_op,
289	     Tensor<SrcEngine, SrcLayout> const& src,
290	     Tensor<DstEngine, DstLayout>      & dst)
291	{
292	  if constexpr (is_constant<true, decltype(size(src) == size(dst))>::value) {
293	    auto dst_null = nullspace(dst.layout());
294	
295	    Tensor dst_n = zipped_divide(dst, dst_null);
296	    Tensor src_n = zipped_divide(src, dst_null);
297	
298	    CUTE_STATIC_ASSERT_V(cosize<0>(dst_n.layout()) == Int<1>{}, "Nullspace definition error");
299	    CUTE_STATIC_ASSERT_V(cosize<0>(src_n.layout()) == Int<1>{}, "Error: Ambiguous race-condition detected.");
300	
301	    copy(copy_op.base, src_n(Int<0>{},_), dst_n(Int<0>{},_));
302	  } else {
303	    copy(copy_op.base, src, dst);
304	  }
305	}
