369	#if defined(CUTE_COPY_ATOM_TMA_SM90_ENABLED)
370	template <class... CT_Args,
371	          class SrcEngine, class SrcLayout,
372	          class DstEngine, class DstLayout>
373	CUTE_HOST_DEVICE
374	void
375	copy(Copy_Traits<SM90_BULK_COPY_AUTO, CT_Args...> const& atom,  // Copy_Traits may or may not have the memory barrier in it already
376	     Tensor<SrcEngine, SrcLayout>                 const& src,
377	     Tensor<DstEngine, DstLayout>                      & dst)
378	{
379	  using SrcType = typename SrcEngine::value_type;
380	  using DstType = typename DstEngine::value_type;
381	  static_assert(cute::is_same<SrcType, DstType>::value);
382	  static_assert((is_gmem<SrcEngine>::value && is_smem<DstEngine>::value) ||
383	                (is_smem<SrcEngine>::value && is_gmem<DstEngine>::value),
384	                "Bulk Copy only supports gmem -> smem or smem -> gmem movement.");
385	  // G2S or S2G dispatch
386	  using BULK_COPY_OP = conditional_t<is_gmem<SrcEngine>::value,
387	                                     SM90_BULK_COPY_G2S,
388	                                     SM90_BULK_COPY_S2G>;
389	
390	  // Find the common subtensor of src and dst
391	  auto tiler = max_common_layout(src, dst);
392	  constexpr int vec_elem = decltype(size(tiler))::value;
393	  constexpr int vec_bits = vec_elem * sizeof_bits_v<SrcType>;
394	  static_assert(vec_bits >= 128, "Expected at least 128-bits for BLKCP");
395	
396	  // Construct a new concrete Atom of the vector size
397	  using BulkAtom = Copy_Atom<Copy_Traits<BULK_COPY_OP, Int<vec_bits>, CT_Args...>, SrcType>;
398	  auto bulk_atom = apply(atom.opargs_, [](auto const&... args) { return BulkAtom{args...}; });
399	  return copy(bulk_atom, logical_divide(src, tiler), logical_divide(dst, tiler));
400	}
