template <class Engine, class Layout, class Fn>
CUTE_HOST_DEVICE constexpr
auto
transform(cute::Tensor<Engine,Layout> const& t, Fn const& fn)
{
  return cute::make_tensor(cute::make_transform_iter(fn, t.data()), t.layout());
}

} // end namespace lazy

} // end namespace cute

